The Observer pattern is a behavioral design pattern that defines a one-to-many dependency between objects, where the observed object (the subject) notifies all its subscribed observers of changes in the state of the observed object.
Here's an implementation of the Observer pattern using Python classes:
```python
class Subject(object):
    def __init__(self):
        self._observers = []

    def attach(self, observer):
        if observer not in self._observers:
            self._observers.append(observer)

    def detach(self, observer):
        try:
            self._observers.remove(observer)
        except ValueError:
            pass

    def notify(self, *args, **kwargs):
        for observer in self._observers:
            observer.update(*args, **kwargs)

class Observer(object):
    def update(self, *args, **kwargs):
        raise NotImplementedError()

class ConcreteObserver(Observer):
    def update(self, message):
        print("Received: {0}".format(message))

subject = Subject()
observer1 = Observer()
observer2 = Observer()

subject.attach(observer1)
subject.attach(observer2)

subject.notify("Hello", "World")  # Output: Received: Hello World
